import React, { useState, useEffect } from 'react';
import { LoadScript, GoogleMap, Marker } from '@react-google-maps/api';
import WebSocketService from '../services/WebSocketService';
import mapStyles from '../components/mapStyles';
import Charts from '../components/Charts';
import StatCard from '../components/StatCard';

const DashboardHome = () => {
  const [vehicles, setVehicles] = useState([]);
  const [alerts, setAlerts] = useState([]);
  const [mapError, setMapError] = useState(null);

  const mapContainerStyle = {
    height: '400px',
    width: '100%',
  };

  const center = {
    lat: 37.7749, // Default: San Francisco
    lng: -122.4194,
  };

  useEffect(() => {
    WebSocketService.connect();

    WebSocketService.subscribe('/topic/vehicles', (message) => {
      const vehicleData = JSON.parse(message.body);
      setVehicles(vehicleData); // Expect array of { id, status, lat, lng }
    });

    WebSocketService.subscribe('/topic/alerts', (message) => {
      const alertData = JSON.parse(message.body);
      setAlerts(alertData.slice(0, 5)); // Show recent 5 alerts
    });

    return () => {
      WebSocketService.disconnect();
    };
  }, []);

  // Stat card data
  const activeVehicles = vehicles.filter(v => v.status === 'ACTIVE').length;
  const totalAlerts = alerts.length;
  const maintenanceVehicles = vehicles.filter(v => v.status === 'MAINTENANCE').length;

  return (
    <div className="p-6">
      <h1 className="text-2xl font-semibold text-gray-800 mb-6 g-brand">Fleet Dashboard</h1>

      {/* Stat Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-6">
        <StatCard title="Active Vehicles" value={activeVehicles} icon="truck" color="bg-blue-500" />
        <StatCard title="Recent Alerts" value={totalAlerts} icon="bell" color="bg-red-500" />
        <StatCard title="Vehicles in Maintenance" value={maintenanceVehicles} icon="wrench" color="bg-yellow-500" />
      </div>

      {/* Google Map */}
      <div className="stat-card mb-6">
        <h2 className="text-lg font-semibold mb-4">Vehicle Locations</h2>
        {mapError ? (
          <div className="g-error">Failed to load map</div>
        ) : (
          <LoadScript
            googleMapsApiKey="YOUR_GOOGLE_MAPS_API_KEY"
            onError={() => setMapError('Failed to load Google Maps')}
          >
            <GoogleMap
              mapContainerStyle={mapContainerStyle}
              center={center}
              zoom={12}
              options={{ styles: mapStyles.light }}
            >
              {vehicles.map((vehicle) => (
                <Marker
                  key={vehicle.id}
                  position={{ lat: vehicle.lat, lng: vehicle.lng }}
                  label={vehicle.status[0]}
                  icon={{
                    url: `/icons/vehicle-${vehicle.status.toLowerCase()}.svg`,
                    scaledSize: new window.google.maps.Size(32, 32),
                  }}
                />
              ))}
            </GoogleMap>
          </LoadScript>
        )}
      </div>

      {/* Charts */}
      <div className="mb-6">
        <Charts />
      </div>

      {/* Recent Alerts */}
      <div className="stat-card">
        <h2 className="text-lg font-semibold mb-4">Recent Alerts</h2>
        {alerts.length === 0 ? (
          <p className="text-gray-600">No recent alerts</p>
        ) : (
          <ul className="list-disc pl-5">
            {alerts.map((alert, index) => (
              <li key={index} className="text-gray-700 mb-2">
                {alert.type} (Vehicle {alert.vehicleId}) - {new Date(alert.timestamp).toLocaleTimeString()}
              </li>
            ))}
          </ul>
        )}
      </div>
    </div>
  );
};

export default DashboardHome;
